)

export const AutocompleteDynamicallyUpdatedData = () => (
  <Wrapper>

      {() => {
        const onTypeHandler = ({
          value,
          showIndicator,
          hideIndicator,
          updateData,
          showNoOptionsItem,
          debounce,
          /* ... */
        }) => {
          console.log('typed value:', value)

          showIndicator()
          debounce(
            ({ value }) => {
              console.log('debounced value:', value)

              const normalizedValue = value.trim().toLowerCase()

              const filteredData = topMovies.filter(({ content }) => {
                if (typeof content === 'string') {
                  return content.toLowerCase().includes(normalizedValue)
                }

                if (Array.isArray(content)) {
                  return content
                    .filter((part) => typeof part === 'string')
                    .join(' ')
                    .toLowerCase()
                    .includes(normalizedValue)
                }

                return false
              })

              const newData =
                normalizedValue.length > 0 ? filteredData : topMovies

              // simulate server delay
              const timeout = setTimeout(() => {
                // update the drawerList
                updateData(newData)
                hideIndicator()

                if (newData.length === 0) {
                  showNoOptionsItem()
                }
              }, 600)

              // cancel invocation method
              return () => clearTimeout(timeout)
            },
            { value },
            250
          )
        }
        return (
          <Autocomplete
            mode="async"
            onType={onTypeHandler}
            noScrollAnimation={true}
            placeholder="Search ..."
          />
        )
      }}

  </Wrapper>
)

export const AutocompleteFirstFocusUpdate = () => (
  <Wrapper>

      {() => {
        const onFocusHandler = ({
          updateData,
          dataList,
          showIndicatorItem,
        }) => {
          if (!dataList.length) {
            showIndicatorItem()
            setTimeout(() => {
              updateData(topMovies)
            }, 1e3)
          }
        }

        return (
          <Autocomplete
            mode="async"
            noScrollAnimation={true}
            preventSelection={true}
            onType={({ value /* updateData, ... */ }) => {
              console.log('onType', value)
            }}
            onFocus={onFocusHandler}
          />
        )
      }}

  </Wrapper>
)

