export const GlobalStatusAddRemoveItems = () => (

    {() => {
      function AddRemoveItems() {
        const [count, toggleUpdateStatus] = React.useState(0)
        return (
          <>
            <GlobalStatus
              id="custom-status"
              autoScroll={false}
              onClose={() => toggleUpdateStatus(0)}
              onHide={() => toggleUpdateStatus(0)}
            />
            <Button
              text={`Show step #${count}`}
              onClick={() => {
                toggleUpdateStatus(count + 1)
                if (count >= 3) {
                  toggleUpdateStatus(0)
                }
              }}
              top="small"
            />
            {count === 1 && (
              <>
                <GlobalStatus.Add
                  id="custom-status"
                  statusId="custom-id-1"
                  title="New title"
                  text="First long info text ..."
                  item="Item from status #1"
                  onClose={({ statusId }) => {
                    console.log('onClose 1', statusId)
                  }}
                />
                <GlobalStatus.Add
                  id="custom-status"
                  statusId="custom-id-2"
                  text="Second long info text ..."
                  item="Item from status #2"
                  onClose={({ statusId }) => {
                    console.log('onClose 2', statusId)
                  }}
                />
              </>
            )}
            {count === 2 && (
              <GlobalStatus.Remove
                id="custom-status"
                statusId="custom-id-2"
              />
            )}
            {count === 3 && (
              <GlobalStatus.Remove
                id="custom-status"
                statusId="custom-id-1"
              />
            )}
          </>
        )
      }
      return <AddRemoveItems />
    }}

)

export const GlobalStatusScrolling = () => (

    <Button
      text="Scroll to main GlobalStatus"
      onClick={() => {
        GlobalStatus.Update({
          id: 'main-status',
          text: 'Dui consectetur viverra aenean vestibulum ac tristique sem ligula condimentum',
        })
      }}
    />

)

export const GlobalStatusUpdate = () => (

    {() => {
      const Context = React.createContext(null)

      const UpdateDemo = () => {
        const [errorA, setErrorA] = React.useState(false)
        const [errorB, setErrorB] = React.useState(false)

        const [isVisible, setVisibility] = React.useState(false)

        return (
          <Context
            value={{
              errorA,
              errorB,
              setErrorA,
              setErrorB,
              isVisible,
              setVisibility,
            }}
          >
            <UpdateDemoStatus />
            <UpdateDemoTools />
          </Context>
        )
      }

      const UpdateDemoStatus = () => {
        const { errorA, errorB, setErrorA, setErrorB } =
          React.useContext(Context)

        return (
          <>
            <GlobalStatus
              title="Custom Title"
              text="Failure text"
              id="demo-2"
            />
            <Input
              top
              right
              label="Label A"
              placeholder="Placeholder A"
              status={errorA}
              globalStatus={{ id: 'demo-2' }}
              onChange={({ value }) => {
                setErrorA(value)
              }}
            />
            <Input
              top
              label="Label B"
              placeholder="Placeholder B"
              status={errorB}
              globalStatus={{ id: 'demo-2' }}
              onChange={({ value }) => {
                setErrorB(value)
              }}
            />
          </>
        )
      }

      const UpdateDemoTools = () => {
        const {
          errorA,
          errorB,
          setErrorA,
          setErrorB,
          isVisible,
          setVisibility,
        } = React.useContext(Context)

        // Only to demonstrate the usage of an interceptor situation
        const inst = React.useRef(null)
        React.useEffect(() => {
          if (!inst.current) {
            inst.current = GlobalStatus.create({
              id: 'demo-2',
              title: 'New Title',
              text: 'New Text',
              statusId: 'custom-item',
              show: false,
            })

            inst.current.update({
              onShow: () => {
                console.log('onShow')
                if (!isVisible) {
                  setVisibility(true)
                }
              },
              onHide: () => {
                console.log('onHide')
                setVisibility(false)
              },
              onClose: () => {
                console.log('onClose')
                setVisibility(false)
              },
            })
          }

          inst.current.update({
            show: isVisible,
          })
        }, [isVisible])
        React.useEffect(() => () => inst.current.remove(), [])

        return (
          <Section top innerSpace={{ block: 'large' }} variant="divider">
            <ToggleButton
              text="Toggle"
              variant="checkbox"
              right
              checked={isVisible}
              onChange={({ checked }) => {
                setVisibility(checked)
              }}
            />
            <Button
              text="Reset"
              variant="tertiary"
              icon="reset"
              disabled={!(errorA || errorB)}
              onClick={() => {
                setErrorA(null)
                setErrorB(null)
              }}
            />
          </Section>
        )
      }

      return <UpdateDemo />
    }}

)

