import React from 'react'
import { StepIndicator, Space, Button, Section } from '@dnb/eufemia/src'

export const StepIndicatorStatic = () => (

    <StepIndicator
      mode="static"
      currentStep={1}
      onChange={({ currentStep }) => {
        console.log('onChange', currentStep)
      }}
      data={[
        {
          title: 'Om din nye bolig',
        },
        {
          title: 'Ditt lån og egenkapital',
          onClick: ({ currentStep }) => console.log(currentStep),
        },
        {
          title: 'Oppsummering',
        },
      ]}
    />

)

export const StepIndicatorStrict = () => (

    <StepIndicator
      mode="strict"
      currentStep={1}
      onChange={({ currentStep }) => {
        console.log('onChange', currentStep)
      }}
      data={[
        {
          title: 'Velg mottaker',
        },
        {
          title: 'Bestill eller erstatt',
          onClick: ({ currentStep }) =>
            console.log('currentStep:', currentStep),
          status:
            'Du må velge bestill nytt kort eller erstatt kort for å kunne fullføre bestillingen din.',
        },
        {
          title: 'Oppsummering',
        },
      ]}
    />

)

export const StepIndicatorLoose = () => (

    {() => {
      const InteractiveDemo = () => {
        const [step, setStep] = React.useState(1)

        return (
          <div style={{ display: 'flex' }}>
            <Space stretch>
              <StepIndicator
                mode="loose"
                currentStep={step}
                onChange={({ currentStep }) => {
                  setStep(currentStep)
                }}
                data={[
                  'Cum odio si bolig bla et ta',
                  'Auctor tortor vestibulum placerat bibendum sociis aliquam nunc sed venenatis massa eget duis',
                  'Bibendum sociis',
                ]}
                bottom
              />

              <Button
                variant="secondary"
                onClick={() => {
                  setStep((step) => {
                    if (step >= 2) {
                      step = -1
                    }
                    return step + 1
                  })
                }}
              >
                Next step
              </Button>
            </Space>
          </div>
        )
      }
      return <InteractiveDemo />
    }}

)

export const StepIndicatorCustomized = () => (

    {() => {
      function CustomStepIndicator({ children, data, ...props }) {
        const [step, setStep] = React.useState(0)
        return (
          <>
            <StepIndicator
              mode="loose"
              data={data}
              currentStep={step}
              onChange={({ currentStep }) => setStep(currentStep)}
              bottom
              {...props}
            />
            <Section backgroundColor="lavender" innerSpace>
              {children(step)}
            </Section>
          </>
        )
      }
      return (
        <CustomStepIndicator
          data={[
            {
              title: 'First',
              isCurrent: true,
            },
            {
              title: 'Second',
            },
            {
              title: 'Last',
            },
          ]}
        >
          {(step) => {
            switch (step) {
              case 0:
                return <>Step One</>
              case 1:
                return <>Step Two</>
              default:
                return <>Fallback</>
            }
          }}
        </CustomStepIndicator>
      )
    }}

)

export const StepIndicatorTextOnly = () => (

    <StepIndicator
      expandedInitially
      mode="static"
      currentStep={1}
      data={[
        'Om din nye bolig',
        'Ditt lån og egenkapital',
        'Oppsummering',
      ]}
    />

)

export const StepIndicatorRouter = () => (

    {() => {
      const StepIndicatorWithRouter = () => {
        const [currentStep, setCurrentStep] = React.useState(1)

        React.useEffect(() => {
          const step =
            parseFloat(window.location.search?.replace(/[?]/, '')) || 1
          setCurrentStep(step)
        }, [])

        return (
          <>
            <StepIndicator
              mode="loose"
              currentStep={currentStep - 1}
              onChange={({ currentStep }) => {
                const step = currentStep + 1
                setCurrentStep(step)
                window.history.pushState({}, '', '?' + step)
              }}
              data={[
                {
                  title: 'Om din nye bolig',
                },
                {
                  title: 'Ditt lån og egenkapital',
                },
                {
                  title: 'Oppsummering',
                },
              ]}
            />
          </>
        )
      }
      return <StepIndicatorWithRouter />
    }}

)

export const StepIndicatorStatuses = () => (

    <StepIndicator
      mode="loose"
      currentStep={0}
      data={[
        {
          title: 'Current',
        },
        {
          title: 'Warning',
          status: 'Status message',
          statusState: 'warning',
        },
        {
          title: 'Error',
          status: 'Status message',
          statusState: 'error',
        },
        {
          title: 'Information',
          status: 'Status message',
          statusState: 'information',
        },
      ]}
    />

)

export const StepIndicatorSkeleton = () => (

    <StepIndicator
      mode="static"
      skeleton
      currentStep={1}
