export function createMockFile(name: string, size: number, type: string) {
  if (typeof window === 'undefined' || !window?.File) {
    return undefined
  }
  const file = new File([], name, { type })
  Object.defineProperty(file, 'size', {
    get() {
      return size
    },
  })
  return file
}

