      <Form.Handler
        data={{
          toBe: true,
          notToBe: false,
        }}
      >
        <Form.Visibility pathTrue="/toBe">
          <P>This will show, as long as `toBe` is true.</P>
        </Form.Visibility>
        <Form.Visibility pathTrue="/notToBe">
          <P>This will not show until `notToBe` is true.</P>
        </Form.Visibility>
      </Form.Handler>

  )
}

export const NestedExample = () => {
  return (

      {() => {
        const filterDataHandler = ({ props }) =>
          !props['data-exclude-field']

        const MyForm = () => {
          return (
            <Form.Handler defaultData={{ isVisible: false }}>
              <Flex.Stack>
                <Field.Boolean
                  label="Visible"
                  variant="button"
                  path="/isVisible"
                  data-exclude-field
                />
                <Form.Visibility
                  pathTrue="/isVisible"
                  animate
                  keepInDOM
                  fieldPropsWhenHidden={{ 'data-exclude-field': true }}
                >
                  <Field.Selection
                    label="Choose"
                    variant="radio"
                    value="less"
                    path="/mySelection"
                  >
                    <Field.Option value="less" title="Less" />
                    <Field.Option value="more" title="More" />
                  </Field.Selection>

                  <Form.Visibility
                    visibleWhen={{
                      path: '/mySelection',
                      hasValue: 'more',
                    }}
                    animate
                    keepInDOM
                    fieldPropsWhenHidden={{ 'data-exclude-field': true }}
                  >
                    <Field.String
                      label="My String"
                      path="/myString"
                      value="foo"
                    />
                  </Form.Visibility>
                </Form.Visibility>
              </Flex.Stack>

              <Output />
            </Form.Handler>
          )
        }

        const Output = () => {
          const { filterData } = Form.useData()
          const filteredData = filterData(filterDataHandler)

          return <Tools.Log data={filteredData} top />
        }

        return <MyForm />
      }}

  )
}

export const FilterData = () => {
  return (

      {() => {
        const filterDataPaths = {
          '/isVisible': false,
          '/mySelection': ({ data }) => data.isVisible,
          '/myString': ({ data }) => {
            return data.isVisible && data.mySelection === 'more'
          },
        }

        const MyForm = () => {
          return (
            <Form.Handler
              defaultData={{
                myString: 'foo',
              }}
            >
              <Flex.Stack>
                <Field.Boolean
                  label="Visible"
                  variant="button"
                  path="/isVisible"
                  defaultValue={false}
                />
                <Form.Visibility pathTrue="/isVisible" animate>
                  <Field.Selection
                    label="Choose"
                    variant="radio"
                    value="less"
                    path="/mySelection"
                  >
                    <Field.Option value="less" title="Less" />
                    <Field.Option value="more" title="More" />
                  </Field.Selection>

                  <Form.Visibility
                    visibleWhen={{
                      path: '/mySelection',
                      hasValue: 'more',
                    }}
                    animate
                  >
                    <Field.String label="My String" path="/myString" />
                  </Form.Visibility>
                </Form.Visibility>

                <Form.Visibility
                  pathDefined="/myString"
                  filterData={filterDataPaths}
                  animate
                >
                  <Form.Card>
                    <P>
                      Result: <Value.String path="/myString" inline />
                    </P>
                  </Form.Card>
                </Form.Visibility>
              </Flex.Stack>

              <Output />
            </Form.Handler>
          )
        }

        const Output = () => {
          const { filterData } = Form.useData()
          const filteredData = filterData(filterDataPaths)
          return <Tools.Log data={filteredData} top />
        }

        return <MyForm />
      }}

  )
}

export function InheritVisibility() {
  return (

      <Form.Handler>
        <Form.Card>
          <Field.Boolean
            variant="button"
            path="/isVisible"
            defaultValue={true}
          />

          <Form.Visibility pathTrue="/isVisible" animate>
            <Field.Name.First path="/foo" defaultValue="foo" />
            <Field.Name.Last path="/bar" defaultValue="bar" />
