import React from 'react'
import { Flex, HeightAnimation } from '@dnb/eufemia/src'
import {
  Field,
  Form,
  Iterate,
  Tools,
  Value,
  Wizard,
} from '@dnb/eufemia/extensions/forms'

export { ViewAndEditContainer } from '../Array/Examples'

export const InitiallyOpen = () => {
