export const IsolatedData = () => {
  return (

      {() => {
        const formData = {
          persons: [
            {
              firstName: 'Ola',
              lastName: 'Nordmann',
            },
            {
              firstName: 'Kari',
              lastName: 'Nordmann',
            },
            {
              firstName: 'Per',
              lastName: 'Hansen',
            },
          ],
        }

        function RepresentativesView() {
          return (
            <Iterate.ViewContainer>
              <Value.Composition>
                <Value.String itemPath="/firstName" />
                <Value.String itemPath="/lastName" />
              </Value.Composition>
            </Iterate.ViewContainer>
          )
        }

        function RepresentativesEdit() {
          return (
            <Iterate.EditContainer>
              <Field.Name.First itemPath="/firstName" />
              <Field.Name.Last itemPath="/lastName" />
            </Iterate.EditContainer>
          )
        }

        function ExistingPersonDetails() {
          const { data, getValue } = Form.useData()
          const person = getValue(data['selectedPerson'])?.data || {}

          return (
            <Flex.Stack>
              <Field.Name.First
                readOnly
                itemPath="/firstName"
                value={person.firstName}
              />
              <Field.Name.Last
                readOnly
                itemPath="/lastName"
                value={person.lastName}
              />
            </Flex.Stack>
          )
        }

        function NewPersonDetails() {
          return (
            <Flex.Stack>
              <Field.Name.First required itemPath="/firstName" />
              <Field.Name.Last required itemPath="/lastName" />
            </Flex.Stack>
          )
        }

        function PushContainerContent() {
          const { data, update } = Form.useData()
          const selectedPerson = data['selectedPerson'] // Because of missing TypeScript support

          // Clear the PushContainer data when the selected person is "other",
          // so the fields do not inherit existing data.
          React.useLayoutEffect(() => {
            if (selectedPerson === 'other') {
              update('/pushContainerItems/0', {})
            }
          }, [selectedPerson, update])

          return (
            <>
              <Field.Selection
                variant="radio"
                required
                path="/selectedPerson"
                dataPath="/persons"
              >
                <Field.Option value="other" label="Other person" />
              </Field.Selection>

              <HeightAnimation top>
                <Form.Visibility
                  visibleWhen={{
                    path: '/selectedPerson',
                    hasValue: (value) =>
                      typeof value === 'string' && value !== 'other',
                  }}
                >
                  <ExistingPersonDetails />
                </Form.Visibility>

                <Form.Visibility
                  visibleWhen={{
                    path: '/selectedPerson',
                    hasValue: (value) => value === 'other',
                  }}
                >
                  <NewPersonDetails />
                </Form.Visibility>
              </HeightAnimation>
            </>
          )
        }

        function RepresentativesCreateNew() {
          return (
            <Iterate.PushContainer
              path="/representatives"
              title="Add new representative"
              isolatedData={{
                persons: formData.persons.map((data, i) => {
                  return {
                    title: [data.firstName, data.lastName].join(' '),
                    value: `/persons/${i}`,
                    data,
                  }
                }),
              }}
              openButton={
                <Iterate.PushContainer.OpenButton
                  variant="tertiary"
                  text="Add new representative"
                />
              }
              showOpenButtonWhen={(list) => list.length > 0}
            >
              <PushContainerContent />
            </Iterate.PushContainer>
          )
        }

        return (
          <Form.Handler>
            <Form.MainHeading>Representatives</Form.MainHeading>
            <Flex.Stack>
              <Form.Card>
                <Iterate.Array path="/representatives">
                  <RepresentativesView />
                  <RepresentativesEdit />
                </Iterate.Array>
                <RepresentativesCreateNew />
              </Form.Card>

              <Form.Card>
                <Form.SubHeading>Data Context</Form.SubHeading>
                <Tools.Log placeholder="-" />
              </Form.Card>
            </Flex.Stack>
          </Form.Handler>
        )
      }}

  )
}

export const PreventUncommittedChanges = () => {
  return (

      <Form.Handler>
        <Wizard.Container>
          <Wizard.Step title="Step 1">
            <Form.Card>
              <Form.SubHeading>People</Form.SubHeading>
              <Iterate.Array
                path="/people"
                animate
                placeholder="No people"
              >
                <Value.Name.First itemPath="/firstName" />
              </Iterate.Array>

              <Iterate.PushContainer
                path="/people"
                title="New person"
                preventUncommittedChanges
                bubbleValidation
                openButton={
                  <Iterate.PushContainer.OpenButton
                    top
                    variant="tertiary"
                    text="Add new person"
                  />
                }
                showOpenButtonWhen={(list) => list.length > 0}
              >
                <Field.Name.First itemPath="/firstName" />
              </Iterate.PushContainer>
            </Form.Card>

            <Wizard.Buttons />
          </Wizard.Step>

          <Wizard.Step title="Step 2">
            <Iterate.Array path="/people">
              <Value.Name.First itemPath="/firstName" />
            </Iterate.Array>
            <Wizard.Buttons />
          </Wizard.Step>
        </Wizard.Container>
      </Form.Handler>

  )
}

export const Variants = () => {
  return (

      <Form.Handler>
        <Wizard.Container>
          <Wizard.Step title="Step 1">
            <Iterate.Array path="/x" required>
              <Value.Address itemPath="/y" />
            </Iterate.Array>
            <Iterate.PushContainer
              path="/x"
              variant="outline"
              top
              bottom
              bubbleValidation
            >
              <Field.Address
                label="variant outline"
                itemPath="/y"
                required
              />
            </Iterate.PushContainer>
            <Iterate.PushContainer
              path="/x"
              variant="filled"
              top
              bottom
              bubbleValidation
            >
              <Field.Address
                label="variant filled"
                itemPath="/y"
                required
              />
            </Iterate.PushContainer>
            <Iterate.PushContainer
              path="/x"
              variant="basic"
              top
              bottom
              bubbleValidation
            >
              <Field.Address
                label="variant basic"
                itemPath="/y"
                required
              />
            </Iterate.PushContainer>
            <Wizard.Buttons />
          </Wizard.Step>
          <Wizard.Step title="Step 2">
            <Wizard.Buttons />
          </Wizard.Step>
        </Wizard.Container>
      </Form.Handler>

  )
}

