import { P } from '@dnb/eufemia/src'
import {
  Field,
  Form,
  Value,
  Wizard,
} from '@dnb/eufemia/extensions/forms'

export const DynamicSteps = () => {
  return (

      <Form.Handler defaultData={{ includedSteps: 'group-1' }}>
        <Wizard.Container
          onStepChange={(index, mode, args) => {
            console.log('onStepChange', index, mode, args.id)
          }}
        >
          <Wizard.Step
            title="Step A"
            id="step-a"
            includeWhen={{ path: '/includedSteps', hasValue: 'group-1' }}
          >
            <Form.MainHeading>Step A</Form.MainHeading>
            <Wizard.Buttons />
          </Wizard.Step>

          <Wizard.Step
            title="Step B"
            id="step-b"
            includeWhen={{ path: '/includedSteps', hasValue: 'group-1' }}
          >
            <Form.MainHeading>Step B</Form.MainHeading>
            <Wizard.Buttons />
          </Wizard.Step>

          <Wizard.Step
            title="Step C"
            id="step-c"
            includeWhen={{
              path: '/includedSteps',
              hasValue: (value: string) =>
                ['group-1', 'group-2'].includes(value),
            }}
          >
            <Form.MainHeading>Step C</Form.MainHeading>
            <Wizard.Buttons />
          </Wizard.Step>

          <Wizard.Step
            title="Step D"
            id="step-d"
            includeWhen={{ path: '/includedSteps', hasValue: 'group-2' }}
          >
            <Form.MainHeading>Step D</Form.MainHeading>
            <Wizard.Buttons />
          </Wizard.Step>
        </Wizard.Container>

        <Field.Selection
          path="/includedSteps"
          variant="button"
          optionsLayout="horizontal"
          top
        >
          <Field.Option value="group-1" title="Group 1" />
          <Field.Option value="group-2" title="Group 2" />
        </Field.Selection>
      </Form.Handler>

  )
}

export const Inactive = () => {
  return (

      {() => {
        const Component = () => {
          const { activeIndex } = Wizard.useStep('unique-id-inactive')

          return (
            <Wizard.Container
              mode="strict"
              id="unique-id-inactive"
              initialActiveIndex={2}
              expandedInitially
            >
              <Wizard.Step title="Step 1" inactive>
                <Wizard.Buttons />
              </Wizard.Step>

              <Wizard.Step title="Step 2" inactive={activeIndex < 1}>
                <Wizard.Buttons />
              </Wizard.Step>

              <Wizard.Step title="Step 3" inactive={activeIndex < 2}>
                <Wizard.Buttons />
              </Wizard.Step>
              <Wizard.Step title="Step 4" inactive={activeIndex < 3}>
                <Wizard.Buttons />
              </Wizard.Step>
            </Wizard.Container>
          )
        }

        return <Component />
      }}

  )
}

